 @inject NotificationService Svc
 @implements IDisposable

 <PageTitle>Notifications</PageTitle>

 <h1>
     Notifications
     <span class="badge bg-primary rounded-pill">@notifications.Count</span>
 </h1>

 @if (notifications.Count == 0)
 {
     <p><em>No notifications yet.</em></p>
 }
 else
 {
     <ul class="list-group">
         @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
         {
             <li class="list-group-item d-flex justify-content-between align-items-start">
                 <div>@n.Message</div>
                 <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
             </li>
         }
     </ul>
 }

 @code {
     [PersistentState]
     public List<NotificationItem> notifications { get; set; } = new();

     private CancellationTokenSource? _cts;

     protected override void OnInitialized()
     {
         // Only fetch if state wasn't restored from prerender
         notifications ??= Svc.GetAll();
         if (notifications.Count == 0)
         {
             notifications = Svc.GetAll();
         }
     }

     protected override void OnAfterRender(bool firstRender)
     {
         if (firstRender)
         {
             // Start polling only after the component is interactive in the browser.
             // OnAfterRender is NOT called during prerender, so this is safe.
             _cts = new CancellationTokenSource();
             _ = PollForNotificationsAsync(_cts.Token);
         }
     }

     private async Task PollForNotificationsAsync(CancellationToken ct)
     {
         while (!ct.IsCancellationRequested)
         {
             try
             {
                 await Task.Delay(TimeSpan.FromSeconds(5), ct);
             }
             catch (OperationCanceledException)
             {
                 break;
             }

             // Simulate new notifications arriving server-side
             Svc.SimulateNewNotification();

             var latest = notifications.Count > 0
                 ? notifications.Max(n => n.Timestamp)
                 : DateTime.MinValue;

             var newItems = Svc.GetSince(latest);
             if (newItems.Count > 0)
             {
                 notifications.AddRange(newItems);
                 await InvokeAsync(StateHasChanged);
             }
         }
     }

     public void Dispose()
     {
         _cts?.Cancel();
         _cts?.Dispose();
     }
 }

