             notifications = Svc.GetAll();
         }
     }

     protected override void OnAfterRender(bool firstRender)
     {
         if (firstRender)
         {
             // Start polling only after the component is interactive in the browser.
             // OnAfterRender is NOT called during prerender, so this is safe.
             _cts = new CancellationTokenSource();
             _ = PollForNotificationsAsync(_cts.Token);
         }
     }

     private async Task PollForNotificationsAsync(CancellationToken ct)
     {
         while (!ct.IsCancellationRequested)
         {
             try
             {
                 await Task.Delay(TimeSpan.FromSeconds(5), ct);
             }
             catch (OperationCanceledException)
             {
                 break;
             }

             // Simulate new notifications arriving server-side
             Svc.SimulateNewNotification();

             var latest = notifications.Count > 0
                 ? notifications.Max(n => n.Timestamp)
                 : DateTime.MinValue;

             var newItems = Svc.GetSince(latest);
             if (newItems.Count > 0)
             {
                 notifications.AddRange(newItems);
                 await InvokeAsync(StateHasChanged);
             }
         }
     }

     public void Dispose()
     {
         _cts?.Cancel();
         _cts?.Dispose();
     }
 }

